import math

import torch
import torch.nn as nn
import torch.nn.functional as F
import nnscaler

from .linear import MixPrecisionLinear

@torch.compile
def swiglu(x: torch.Tensor, gate: torch.Tensor) -> torch.Tensor:
    return x * F.silu(gate)

nnscaler.register_op('l d, l d -> l d')(swiglu)

class FeedForwardNetwork(nn.Module):
    def __init__(
        self,
        embed_dim,
        ffn_dim
    ):
        super().__init__()
        self.embed_dim = embed_dim
        self.up_proj = MixPrecisionLinear(self.embed_dim, ffn_dim, bias=False)
        self.down_proj = MixPrecisionLinear(ffn_dim, self.embed_dim, bias=False)
        self.gate_proj = MixPrecisionLinear(self.embed_dim, ffn_dim, bias=False)
        self.init_weights()

    def init_weights(self):
        nn.init.kaiming_uniform_(self.up_proj.weight, a=math.sqrt(5), mode='fan_in')
        nn.init.kaiming_uniform_(self.gate_proj.weight, a=math.sqrt(5), mode='fan_in')
        nn.init.kaiming_uniform_(self.down_proj.weight, a=math.sqrt(5), mode='fan_out')

    def forward(self, x):
        return self.down_proj(swiglu(self.up_proj(x), self.gate_proj(x)))

import torch
from torch import nn
import torch.nn.functional as F
from torch.autograd import Function
from kernel.utils import is_hip

if is_hip():
    def grad_weight_linear(input, grad_output):
        return torch.mm(grad_output.t(), input).to(torch.float32)
else:
    def grad_weight_linear(input, grad_output):
        return torch.mm(grad_output.t(), input, out_dtype=torch.float32)

class LinearBF16ToFP32Grad(Function):
    @staticmethod
    def forward(ctx, input, weight):
        assert input.dtype == torch.bfloat16, "input must be bfloat16"
        weight = weight.to(input.dtype)
        ctx.save_for_backward(input, weight)
        return F.linear(input, weight)

    @staticmethod
    def backward(ctx, grad_output):
        input, weight = ctx.saved_tensors
        grad_input = grad_weight = None

        if ctx.needs_input_grad[0]:
            grad_input = F.linear(grad_output, weight.t())

        if ctx.needs_input_grad[1]:
            grad_weight = grad_weight_linear(input, grad_output)

        return grad_input, grad_weight

def mix_precision_linear(input, weight):
    return LinearBF16ToFP32Grad.apply(input, weight)

import nnscaler
nnscaler.register_op('* k+, n k+ -> * n')(mix_precision_linear)

class MixPrecisionLinear(nn.Linear):
    def __init__(self, in_features, out_features, bias=False):
        assert bias is False, "bias is not supported for MixPrecisionLinear"
        super().__init__(in_features, out_features, bias)

    def forward(self, input):
        return mix_precision_linear(input, self.weight)

